<?php namespace App\Console\Commands; use Illuminate\Console\Command; use App\Domain\Entities\User; class CheckMemoryLeak extends Command { protected $signature = 'check:memory'; public function handle() { $user = User::where('email', 'admin@financial.system')->first(); auth()->login($user); $component = app(\App\Livewire\Dashboard::class); app()->call([$component, 'boot']); $component->mount(); $this->info('memory after mount: ' . memory_get_usage()); try { $component->render(); } catch (\Throwable $e) { dump($e->getMessage()); } $this->info('memory after render: ' . memory_get_usage()); } }
